import { validateUuid } from "@hackerspub/models/uuid";
import type { APIEvent } from "@solidjs/start/server";

function escapeHtml(s: string): string {
  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

export function GET({ params, request }: APIEvent) {
  const { token } = params;
  if (!validateUuid(token)) {
    return new Response("Invalid token", { status: 400 });
  }

  const url = new URL(request.url);
  const code = url.searchParams.get("code");
  if (code == null) {
    return new Response("Missing code", { status: 400 });
  }

  const appLink = `hackerspub://verify?token=${
    encodeURIComponent(token)
  }&code=${encodeURIComponent(code)}`;
  const intentLink =
    `intent://verify?token=${encodeURIComponent(token)}&code=${
      encodeURIComponent(code)
    }#Intent;scheme=hackerspub;package=pub.hackers.android;end`;
  const webFallback = `/sign/in/${encodeURIComponent(token)}?code=${
    encodeURIComponent(code)
  }`;

  const html = `<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Opening Hackers' Pub...</title>
<script>
  var appLink = ${JSON.stringify(appLink)};
  var intentLink = ${JSON.stringify(intentLink)};
  var webFallback = ${JSON.stringify(webFallback)};
  var isAndroid = /Android/i.test(navigator.userAgent);

  if (!isAndroid) {
    window.location.href = webFallback;
  } else {
    var didHide = false;
    document.addEventListener("visibilitychange", function() {
      if (document.hidden) didHide = true;
    });
    if (/Chrome/i.test(navigator.userAgent)) {
      window.location.href = intentLink;
    } else {
      window.location.href = appLink;
    }
    setTimeout(function() {
      if (!didHide) window.location.href = webFallback;
    }, 2000);
  }
</script>
</head>
<body>
<p>Opening Hackers' Pub app...</p>
<p><a href="${escapeHtml(webFallback)}">Continue in browser</a></p>
</body>
</html>`;

  return new Response(html, {
    headers: { "Content-Type": "text/html; charset=utf-8" },
  });
}

